css:
* { margin: 0; padding: 0; box-sizing: border-box; }
body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; background: #09090f; color: white; }
nav { display: flex; align-items: center; justify-content: space-between; padding: 0 72px; height: 80px; border-bottom: 1px solid rgba(255,255,255,0.07); }
.logo { font-size: 24px; font-weight: 900; letter-spacing: 4px; color: white; }
.links { display: flex; gap: 32px; } .links a { color: #64748b; text-decoration: none; font-weight: 500; transition: color 0.2s; } .links a:hover { color: white; }
.cta { padding: 12px 24px; border-radius: 12px; border: none; background: linear-gradient(135deg, #ec4899, #f97316); color: white; font-weight: 700; cursor: pointer; }
.hero { display: grid; grid-template-columns: 1fr 1fr; gap: 80px; align-items: center; padding: 100px 72px; min-height: calc(100vh - 80px); }
.label { display: inline-block; color: #ec4899; font-size: 13px; font-weight: 700; letter-spacing: 3px; margin-bottom: 24px; }
h1 { font-size: 80px; font-weight: 900; line-height: 0.95; letter-spacing: -3px; margin-bottom: 28px; } h1 em { font-style: normal; background: linear-gradient(135deg, #ec4899, #f97316); -webkit-background-clip: text; -webkit-text-fill-color: transparent; }
.hero-text p { color: #64748b; font-size: 18px; line-height: 1.7; margin-bottom: 36px; max-width: 440px; }
.actions { display: flex; gap: 16px; }
.btn-main { padding: 16px 32px; border-radius: 14px; border: none; background: white; color: #09090f; font-weight: 800; font-size: 15px; cursor: pointer; }
.btn-outline { padding: 16px 32px; border-radius: 14px; border: 1px solid rgba(255,255,255,0.2); background: transparent; color: white; font-weight: 600; font-size: 15px; cursor: pointer; }
.visual-grid { display: grid; grid-template-columns: 1.5fr 1fr; grid-template-rows: 1fr 1fr; gap: 16px; height: 400px; }
.v-card { border-radius: 20px; display: flex; align-items: flex-end; padding: 20px; font-weight: 800; font-size: 18px; }
.v-card.big { grid-row: span 2; } .v-card.purple { background: linear-gradient(135deg, #7c3aed, #a855f7); } .v-card.orange { background: linear-gradient(135deg, #ea580c, #f97316); } .v-card.pink { background: linear-gradient(135deg, #be185d, #ec4899); } .v-card.blue { background: linear-gradient(135deg, #1d4ed8, #3b82f6); }
.services { padding: 80px 72px; }
.s-header { margin-bottom: 48px; } .s-tag { color: #ec4899; font-size: 13px; font-weight: 700; letter-spacing: 3px; display: block; margin-bottom: 12px; } .s-header h2 { font-size: 48px; font-weight: 900; }
.s-grid { display: grid; grid-template-columns: repeat(4, 1fr); gap: 24px; }
.s-card { padding: 32px; border-radius: 20px; border: 1px solid rgba(255,255,255,0.08); background: rgba(255,255,255,0.03); transition: border-color 0.3s; } .s-card:hover { border-color: rgba(236,72,153,0.4); }
.s-num { font-size: 48px; font-weight: 900; color: rgba(255,255,255,0.08); margin-bottom: 16px; } .s-card h3 { font-size: 18px; font-weight: 700; margin-bottom: 10px; } .s-card p { color: #64748b; line-height: 1.6; font-size: 14px; }
.stats { display: flex; justify-content: center; gap: 80px; padding: 60px 72px; border-top: 1px solid rgba(255,255,255,0.07); } .stat { text-align: center; } .stat strong { display: block; font-size: 52px; font-weight: 900; background: linear-gradient(135deg, #ec4899, #f97316); -webkit-background-clip: text; -webkit-text-fill-color: transparent; } .stat span { color: #475569; font-size: 14px; }
